<span class="line"><span style="color:#F9E2AF;">            serde_json</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">to_string_pretty</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">t</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">parameters</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap_or_default</span><span style="color:#9399B2;">()</span></span>
